func installedEntryRootCandidate(entry registry.InstalledEntry) string {
	if len(entry.Files) > 0 && strings.TrimSpace(entry.Files[0]) != "" {
		return entry.Files[0]
	}
	return strings.TrimSpace(entry.Source)
